import * as React from 'react';
import './style/index.css';

function LoadingLight(props) {
    const { size = 'normal', svgSource } = props;
    let loadingSize;
    if (size === 'normal') {
        loadingSize = 120;
    }
    else if (size === 'small') {
        loadingSize = 100;
    }
    else {
        loadingSize = size;
    }
    loadingSize = typeof loadingSize === 'number' ? `${loadingSize}px` : loadingSize;
    const style = {
        ...props.style,
        width: loadingSize,
        height: loadingSize,
        overflow: "hidden",
        backgroundSize: `auto ${loadingSize}`,
        backgroundImage: `url(${svgSource})`
    };
    const classNames = `ud__illustration__loading-container ` + (props.classNames || '');
    return (React.createElement("div", { className: classNames, style: style }));
}

export { LoadingLight as default };
